const message = $input.first().json.text || "";

const urlPatterns = [
  /https?:\/\/(?:www\.)?youtube\.com\/watch\?v=([a-zA-Z0-9_-]+)/,
  /https?:\/\/youtu\.be\/([a-zA-Z0-9_-]+)/,
  /https?:\/\/(?:www\.)?youtube\.com\/live\/([a-zA-Z0-9_-]+)/,
  /https?:\/\/(?:www\.)?youtube\.com\/shorts\/([a-zA-Z0-9_-]+)/
];

let videoId = null;
let videoUrl = null;

for (const pattern of urlPatterns) {
  const match = message.match(pattern);
  if (match) {
    videoId = match[1];
    videoUrl = match[0];
    break;
  }
}

if (!videoId) {
  throw new Error("No YouTube URL found in message");
}

const today = new Date().toISOString().split("T")[0];

return [{
  json: {
    videoId,
    videoUrl,
    originalMessage: message,
    user: $input.first().json.user || "unknown",
    timestamp: today
  }
}];

const transcript = $input.first().json;
const urlData = $('Extract Video ID').first().json;

const title = transcript.title || "Untitled Video";
const channel = transcript.channelName || transcript.channel || "Unknown Channel";
const duration = transcript.duration || "Unknown";
const rawTranscript = transcript.transcript || transcript.text || "No transcript available";

// Generate a clean filename slug
const slug = title
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '')
  .substring(0, 60);

// Build the markdown file content
const fileContent = `---\ntitle: "${title.replace(/"/g, '\\"')}"\nchannel: "${channel.replace(/"/g, '\\"')}"\nurl: "${urlData.videoUrl}"\nduration: "${duration}"\ncaptured: "${urlData.timestamp}"\nprocessed: false\n---\n\n# ${title}\n**Channel:** ${channel}\n**URL:** ${urlData.videoUrl}\n**Duration:** ${duration}\n**Captured:** ${urlData.timestamp}\n\n---\n\n## Raw Transcript\n\n${rawTranscript}\n`;

return [{
  json: {
    fileName: slug + '.md',
    filePath: 'research/youtube-transcripts/' + slug + '.md',
    fileContent,
    commitMessage: 'youtube-transcript: ' + title,
    title,
    channel,
    videoUrl: urlData.videoUrl,
    slug
  }
}];
